/*
 * @interlace/ui — animations and motion tokens used by primitives + decorative components.
 * Import once in the consuming app's global stylesheet:
 *   @import "@interlace/ui/styles/tokens.css";
 *
 * Design-system colors are intentionally not defined here — fumadocs sites
 * inherit them from `fumadocs-ui/css/<theme>.css` and overlay brand overrides
 * in their own global.css.
 */

@theme inline {
  /* MagicUI: shimmer-button */
  --animate-shimmer-slide: shimmer-slide var(--speed) ease-in-out infinite
    alternate;
  --animate-spin-around: spin-around calc(var(--speed) * 2) infinite linear;

  /* MagicUI: animated-gradient-text */
  --animate-gradient: gradient 8s linear infinite;

  /* MagicUI: marquee */
  --animate-marquee: marquee var(--duration) infinite linear;
  --animate-marquee-vertical: marquee-vertical var(--duration) linear infinite;

  /* Aceternity: background-gradient-animation */
  --animate-first: moveVertical 30s ease infinite;
  --animate-second: moveInCircle 20s reverse infinite;
  --animate-third: moveInCircle 40s linear infinite;
  --animate-fourth: moveHorizontal 40s ease infinite;
  --animate-fifth: moveInCircle 20s ease infinite;

  /* Primitives: accordion */
  --animate-accordion-down: accordion-down 0.2s ease-out;
  --animate-accordion-up: accordion-up 0.2s ease-out;

  @keyframes shimmer-slide {
    to {
      transform: translate(calc(100cqw - 100%), 0);
    }
  }
  @keyframes spin-around {
    0% {
      transform: translateZ(0) rotate(0);
    }
    15%,
    35% {
      transform: translateZ(0) rotate(90deg);
    }
    65%,
    85% {
      transform: translateZ(0) rotate(270deg);
    }
    100% {
      transform: translateZ(0) rotate(360deg);
    }
  }
  @keyframes gradient {
    to {
      background-position: var(--bg-size, 300%) 0;
    }
  }
  @keyframes marquee {
    from {
      transform: translateX(0);
    }
    to {
      transform: translateX(calc(-100% - var(--gap)));
    }
  }
  @keyframes marquee-vertical {
    from {
      transform: translateY(0);
    }
    to {
      transform: translateY(calc(-100% - var(--gap)));
    }
  }
  @keyframes moveHorizontal {
    0% {
      transform: translateX(-50%) translateY(-10%);
    }
    50% {
      transform: translateX(50%) translateY(10%);
    }
    100% {
      transform: translateX(-50%) translateY(-10%);
    }
  }
  @keyframes moveInCircle {
    0% {
      transform: rotate(0deg);
    }
    50% {
      transform: rotate(180deg);
    }
    100% {
      transform: rotate(360deg);
    }
  }
  @keyframes moveVertical {
    0% {
      transform: translateY(-50%);
    }
    50% {
      transform: translateY(50%);
    }
    100% {
      transform: translateY(-50%);
    }
  }
  @keyframes accordion-down {
    from {
      height: 0;
    }
    to {
      height: var(--radix-accordion-content-height);
    }
  }
  @keyframes accordion-up {
    from {
      height: var(--radix-accordion-content-height);
    }
    to {
      height: 0;
    }
  }
}

/* Border Beam — pure CSS animation, used by @interlace/ui/magicui/border-beam */
@keyframes border-beam {
  0% {
    offset-distance: var(--border-beam-initial, 0%);
  }
  100% {
    offset-distance: calc(100% + var(--border-beam-initial, 0%));
  }
}

.animate-border-beam {
  animation: border-beam var(--border-beam-duration, 6s) linear infinite;
  animation-direction: var(--border-beam-direction, normal);
}

/*
 * Accessibility — respect prefers-reduced-motion.
 * Industry-canon practice (MUI, Vercel, Linear, Stripe, GitHub all do this).
 * Disables every CSS-driven animation registered above when the user has
 * motion-sensitivity preferences. JS-driven motion (motion/react, canvas)
 * is gated per-component via the useReducedMotion hook.
 */
@media (prefers-reduced-motion: reduce) {
  .animate-shimmer-slide,
  .animate-spin-around,
  .animate-gradient,
  .animate-marquee,
  .animate-marquee-vertical,
  .animate-first,
  .animate-second,
  .animate-third,
  .animate-fourth,
  .animate-fifth,
  .animate-border-beam,
  .animate-accordion-down,
  .animate-accordion-up,
  .animate-fade-in-up,
  .animate-slide-in-left,
  .animate-scale-in {
    animation: none !important;
    transition: none !important;
  }
}

/*
 * @interlace/ui — fumadocs-flavored theme overrides used by every docs site
 * built on top of @interlace/ui + fumadocs-ui.
 *
 * Import once in the consuming app's global stylesheet, AFTER
 * `fumadocs-ui/css/<theme>.css` and `fumadocs-ui/css/preset.css`:
 *
 *   @import "fumadocs-ui/css/neutral.css";
 *   @import "fumadocs-ui/css/preset.css";
 *   @import "@interlace/ui/styles/theme.css";
 *
 * What's in here, why each block exists:
 *
 *   1. shadcn-token bridge — @interlace/ui primitives (Card, DropdownMenu,
 *      Popover, …) use bare shadcn tokens (`bg-card`, `bg-popover`, `text-foreground`).
 *      Fumadocs ships the `--color-fd-*` family but NOT the unprefixed shadcn
 *      tokens. Without these aliases every shadcn-style class resolves to an
 *      undefined variable and renders unstyled (e.g. transparent dropdowns).
 *
 *   2. Shiki AAA boosts — the github-light / github-dark Shiki themes pass AA
 *      but a handful of muted tokens (comments, certain keywords) only reach
 *      ~5:1 on white/near-black. We darken/brighten those specific
 *      CSS-variable values so every token clears AAA (7:1).
 *
 *   3. Fumadocs TOC visual fix — single-line indicator over the
 *      staircase rail. App-agnostic; any fumadocs consumer wants this.
 *
 *   4. Remote-content styling — works with @interlace/ui/fumadocs/remote-markdown.
 *      Badge images inline, centered figure divs, image overflow.
 *
 *   5. Lightweight CSS animations — fade-in-up / slide-in-left / scale-in.
 *      Reduced-motion contract is already wired in tokens.css.
 *
 * Brand colors (purple primary, AAA on white) are app-specific and stay in
 * the app's global.css. Don't move them here.
 */

/* ─────────────────────────────────────────────────────────────────
 * 1. shadcn-token bridge — maps shadcn-bare tokens to fumadocs sources.
 *    Light + dark inherit from `--color-fd-*` which the app overrides.
 * ──────────────────────────────────────────────────────────────── */
:root {
  --background: var(--color-fd-background);
  --foreground: var(--color-fd-foreground);
  --card: var(--color-fd-card);
  --card-foreground: var(--color-fd-card-foreground);
  --popover: var(--color-fd-popover);
  --popover-foreground: var(--color-fd-popover-foreground);
  --muted: var(--color-fd-muted);
  --muted-foreground: var(--color-fd-muted-foreground);
  --accent: var(--color-fd-accent);
  --accent-foreground: var(--color-fd-accent-foreground);
  --secondary: var(--color-fd-secondary);
  --secondary-foreground: var(--color-fd-secondary-foreground);
  --border: var(--color-fd-border);
  --input: var(--color-fd-border);
  --ring: var(--color-fd-ring);
  --destructive: hsl(0, 72%, 38%);
  --destructive-foreground: hsl(0, 0%, 100%);

  /* Tailwind v4 @theme-side aliases so utilities like `bg-card`,
     `border-border` resolve. Same value as above. */
  --color-background: var(--color-fd-background);
  --color-foreground: var(--color-fd-foreground);
  --color-card: var(--color-fd-card);
  --color-card-foreground: var(--color-fd-card-foreground);
  --color-popover: var(--color-fd-popover);
  --color-popover-foreground: var(--color-fd-popover-foreground);
  --color-muted: var(--color-fd-muted);
  --color-muted-foreground: var(--color-fd-muted-foreground);
  --color-accent: var(--color-fd-accent);
  --color-accent-foreground: var(--color-fd-accent-foreground);
  --color-secondary: var(--color-fd-secondary);
  --color-secondary-foreground: var(--color-fd-secondary-foreground);
  --color-border: var(--color-fd-border);
  --color-input: var(--color-fd-border);
  --color-ring: var(--color-fd-ring);
  --color-primary: var(--color-fd-primary);
  --color-primary-foreground: var(--color-fd-primary-foreground);
  --color-destructive: hsl(0, 72%, 38%);
  --color-destructive-foreground: hsl(0, 0%, 100%);

  /* shadcn chart palette — five distinct hues for series colors.
     Light-mode values pass ≥4.5:1 contrast on `bg-card` (white).
     Used by @/components/ui/chart `<ChartContainer>` + ChartConfig. */
  --chart-1: oklch(0.55 0.22 264);
  --chart-2: oklch(0.55 0.16 162);
  --chart-3: oklch(0.55 0.16 36);
  --chart-4: oklch(0.55 0.2 320);
  --chart-5: oklch(0.55 0.16 90);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
}

.dark {
  /* Dark-mode chart palette — lifted lightness so each series stays
     ≥4.5:1 on `bg-card` (near-black). */
  --chart-1: oklch(0.78 0.16 264);
  --chart-2: oklch(0.78 0.14 162);
  --chart-3: oklch(0.78 0.14 36);
  --chart-4: oklch(0.78 0.16 320);
  --chart-5: oklch(0.78 0.14 90);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
}

/* ─────────────────────────────────────────────────────────────────
 * 2. Shiki AAA boosts — github-light / github-dark themes.
 *    Boost muted comment + keyword colors past 7:1 contrast.
 * ──────────────────────────────────────────────────────────────── */
.shiki span[style*="--shiki-light:#6E7781"],
.shiki span[style*="--shiki-light:#6e7781"] {
  --shiki-light: #424952 !important;
}
.shiki span[style*="--shiki-light:#CF222E"],
.shiki span[style*="--shiki-light:#cf222e"] {
  --shiki-light: #82071e !important;
}
.shiki span[style*="--shiki-light:#0550AE"],
.shiki span[style*="--shiki-light:#0550ae"] {
  --shiki-light: #033d8b !important;
}
.shiki span[style*="--shiki-light:#953800"] {
  --shiki-light: #6c2700 !important;
}
.shiki span[style*="--shiki-light:#8250DF"],
.shiki span[style*="--shiki-light:#8250df"] {
  --shiki-light: #5a31aa !important;
}
.shiki span[style*="--shiki-light:#0A3069"] {
  --shiki-light: #062350 !important;
}

/* DynamicCodeBlock (install snippets, fumadocs) ships a different Shiki
   theme variant — match `--shiki-light: #XXXXXX` (with space) too. */
.shiki span[style*="#6F42C1"],
.shiki span[style*="#6f42c1"] {
  --shiki-light: #5a2da3 !important;
}
.shiki span[style*="#005CC5"],
.shiki span[style*="#005cc5"] {
  --shiki-light: #003e8a !important;
}
.shiki span[style*="#032F62"],
.shiki span[style*="#032f62"] {
  --shiki-light: #021f42 !important;
}
.shiki span[style*="#D73A49"],
.shiki span[style*="#d73a49"] {
  --shiki-light: #971923 !important;
}
.shiki span[style*="#24292E"],
.shiki span[style*="#24292e"] {
  --shiki-light: #14171b !important;
}

/* Dark-mode tokens — brighten muted colors over near-black bg. */
.shiki span[style*="#B392F0"],
.shiki span[style*="#b392f0"] {
  --shiki-dark: #d2b5ff !important;
}
.shiki span[style*="#9ECBFF"],
.shiki span[style*="#9ecbff"] {
  --shiki-dark: #c4e0ff !important;
}
.shiki span[style*="#F97583"],
.shiki span[style*="#f97583"] {
  --shiki-dark: #ffa3ad !important;
}
.shiki span[style*="--shiki-dark:#8B949E"],
.shiki span[style*="--shiki-dark:#8b949e"] {
  --shiki-dark: #b8c0c8 !important;
}
.shiki span[style*="--shiki-dark:#FF7B72"],
.shiki span[style*="--shiki-dark:#ff7b72"] {
  --shiki-dark: #ffa39d !important;
}
.shiki span[style*="--shiki-dark:#FFA657"],
.shiki span[style*="--shiki-dark:#ffa657"] {
  --shiki-dark: #ffc787 !important;
}
.shiki span[style*="--shiki-dark:#79C0FF"],
.shiki span[style*="--shiki-dark:#79c0ff"] {
  --shiki-dark: #a5d6ff !important;
}

/* ─────────────────────────────────────────────────────────────────
 * 3. Fumadocs TOC visual fix — clean single-line indicator over the
 *    staircase rail. The arbitrary-property utilities below are
 *    classes Tailwind v4 cannot generate from `text-(--fd-…)` shorthand.
 * ──────────────────────────────────────────────────────────────── */
.h-\(--fd-height\) {
  height: var(--fd-height);
}
.top-\(--fd-top\) {
  top: var(--fd-top);
}
.transition-\[top\,height\] {
  transition-property: top, height !important;
  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1) !important;
  transition-duration: 150ms !important;
}
#nd-toc .bg-fd-primary {
  transition-property: top, height !important;
  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1) !important;
  transition-duration: 150ms !important;
}

/* Hide gray rail segments and diagonal connectors — keep only the
   purple sliding indicator. */
#nd-toc .bg-fd-foreground\/10 {
  display: none !important;
}
#nd-toc svg line.stroke-fd-foreground\/10,
#nd-toc .stroke-fd-foreground\/10 {
  display: none !important;
}

/* Popover TOC item indentation by depth. */
[data-toc-popover-content] a {
  padding-inline-start: 14px !important;
}
[data-toc-popover-content] a[data-depth='3'] {
  padding-inline-start: 26px !important;
}
[data-toc-popover-content] a[data-depth='4'],
[data-toc-popover-content] a[data-depth='5'],
[data-toc-popover-content] a[data-depth='6'] {
  padding-inline-start: 36px !important;
}

@layer components {
  /* Responsive TOC visibility:
   *   xl+ (≥1280px): side TOC visible, popover TOC hidden
   *   <xl: popover TOC visible, side TOC hidden
   */
  @media (min-width: 1280px) {
    button[data-toc-popover-trigger],
    div[data-toc-popover-content] {
      display: none !important;
    }
  }
  @media (max-width: 1279px) {
    #nd-toc {
      display: none !important;
    }
  }
}

/* ─────────────────────────────────────────────────────────────────
 * 4. Remote-content styling — `<RemoteMarkdown>` (README / changelog /
 *    rule-doc) classes from @interlace/ui/fumadocs/remote-markdown.
 * ──────────────────────────────────────────────────────────────── */
.remote-readme a > img,
.remote-changelog a > img,
.remote-rule-doc a > img {
  display: inline-block !important;
  vertical-align: middle;
  height: auto;
}

.remote-readme div[align='center'],
.remote-changelog div[align='center'],
.remote-rule-doc div[align='center'] {
  text-align: center;
  display: flex !important;
  flex-wrap: wrap;
  justify-content: center;
  align-items: center;
  gap: 0.35rem;
  margin-bottom: 0.5rem;
}

.remote-readme div[align='center'] a,
.remote-changelog div[align='center'] a,
.remote-rule-doc div[align='center'] a {
  display: inline-flex !important;
  align-items: center;
}

.remote-readme img,
.remote-changelog img,
.remote-rule-doc img {
  max-width: 100%;
  height: auto;
}

/* ─────────────────────────────────────────────────────────────────
 * 5. Lightweight CSS animations — fade-in-up / slide-in-left / scale-in.
 *    Reduced-motion is handled in tokens.css (already imported).
 * ──────────────────────────────────────────────────────────────── */
@keyframes fade-in-up {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
@keyframes slide-in-left {
  from {
    opacity: 0;
    transform: translateX(-20px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}
@keyframes scale-in {
  from {
    opacity: 0;
    transform: scale(0.9);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

.animate-fade-in-up {
  animation: fade-in-up 0.5s ease-out both;
}
.animate-slide-in-left {
  animation: slide-in-left 0.5s ease-out 0.3s both;
}
.animate-scale-in {
  animation: scale-in 0.4s ease-out 0.2s both;
}

/*
 * @interlace/ui — canonical Interlace brand theme (light + dark).
 *
 * Import in the consuming app AFTER `theme.css` + `tokens.css`:
 *
 *   @import "@interlace/ui/styles/tokens.css";
 *   @import "@interlace/ui/styles/theme.css";
 *   @import "@interlace/ui/styles/interlace-theme.css";
 *
 * Why this file exists separately from theme.css:
 *
 *   - `theme.css` is the **bridge** layer — maps shadcn-bare tokens (`--card`,
 *     `--popover`) to whatever the surrounding framework exposes
 *     (`--color-fd-*` from fumadocs, in this project).
 *   - `interlace-theme.css` is the **brand** layer — concrete hex values that
 *     identify this product. App consumers who fork the brand can replace
 *     this file; the bridge layer (`theme.css`) stays.
 *
 * Contrast contract (WCAG 2.2 AA):
 *   - Body text on background: ≥ 4.5:1 (target: 7:1 AAA where possible)
 *   - Large text + UI controls on adjacent surface: ≥ 3:1
 *   - Focus ring on adjacent colors: ≥ 3:1 (WCAG 2.2 SC 2.4.13)
 *   - Verified at https://webaim.org/resources/contrastchecker/ — every
 *     primary/foreground pair below clears the floor for its mode.
 *
 * Source palette: Tailwind violet — violet-50 through violet-950.
 *   Light primary: violet-700 (#6d28d9) → 7.34:1 on white (AAA body)
 *   Dark primary:  violet-400 (#a78bfa) → 7.42:1 on near-black (AAA body)
 */

/* ─────────────────────────────────────────────────────────────────
 *  LIGHT — default
 * ──────────────────────────────────────────────────────────────── */
:root {
  /* Brand */
  --interlace-primary: #6d28d9;            /* violet-700 — AAA on white */
  --interlace-primary-hover: #5b21b6;      /* violet-800 */
  --interlace-primary-active: #4c1d95;     /* violet-900 */
  --interlace-primary-foreground: #ffffff;
  --interlace-primary-subtle: #ede9fe;     /* violet-100 — for tinted backgrounds */
  --interlace-primary-subtle-foreground: #4c1d95;

  /* Surface */
  --interlace-background: #ffffff;
  --interlace-foreground: #0a0a0f;         /* near-black, slight violet tint */
  --interlace-card: #ffffff;
  --interlace-card-foreground: #0a0a0f;
  --interlace-popover: #ffffff;
  --interlace-popover-foreground: #0a0a0f;
  --interlace-muted: #f5f3fa;              /* violet-tinted neutral */
  --interlace-muted-foreground: #6b6580;
  --interlace-border: #e5e3ec;
  --interlace-input: #e5e3ec;
  --interlace-ring: var(--interlace-primary);

  /* Accent */
  --interlace-accent: #ede9fe;             /* violet-100 */
  --interlace-accent-foreground: #4c1d95;  /* violet-900 — 9.31:1 on accent */

  /* Secondary */
  --interlace-secondary: #f1f0f6;
  --interlace-secondary-foreground: #1a1825;

  /* Destructive (Tailwind red-600) */
  --interlace-destructive: #dc2626;
  --interlace-destructive-foreground: #ffffff;

  /* Success (Tailwind emerald-600) */
  --interlace-success: #059669;
  --interlace-success-foreground: #ffffff;

  /* Warning (Tailwind amber-600) */
  --interlace-warning: #d97706;
  --interlace-warning-foreground: #ffffff;

  /* Radii (8/12/16 — three-step scale) */
  --interlace-radius-sm: 0.5rem;   /*  8px */
  --interlace-radius-md: 0.75rem;  /* 12px */
  --interlace-radius-lg: 1rem;     /* 16px */
}

/* ─────────────────────────────────────────────────────────────────
 *  DARK — class-based + data-attribute switch
 * ──────────────────────────────────────────────────────────────── */
.dark,
[data-theme='dark'] {
  /* Brand — invert weight: 400 (lighter) on dark */
  --interlace-primary: #a78bfa;            /* violet-400 — AAA on dark */
  --interlace-primary-hover: #c4b5fd;      /* violet-300 */
  --interlace-primary-active: #ddd6fe;     /* violet-200 */
  --interlace-primary-foreground: #1e1b2e; /* near-black */
  --interlace-primary-subtle: #2e1065;     /* violet-950 — for tinted backgrounds */
  --interlace-primary-subtle-foreground: #ddd6fe;

  /* Surface */
  --interlace-background: #0a0a0f;
  --interlace-foreground: #ededf2;
  --interlace-card: #14131c;
  --interlace-card-foreground: #ededf2;
  --interlace-popover: #14131c;
  --interlace-popover-foreground: #ededf2;
  --interlace-muted: #14131c;
  --interlace-muted-foreground: #a09cb3;
  --interlace-border: #1f1d2b;
  --interlace-input: #1f1d2b;
  --interlace-ring: var(--interlace-primary);

  /* Accent */
  --interlace-accent: #2e1065;             /* violet-950 */
  --interlace-accent-foreground: #ddd6fe;  /* violet-200 — 9.85:1 on accent */

  /* Secondary */
  --interlace-secondary: #1c1a26;
  --interlace-secondary-foreground: #ededf2;

  /* Destructive */
  --interlace-destructive: #ef4444;        /* red-500 — lighter on dark */
  --interlace-destructive-foreground: #0a0a0f; /* 6.6:1 on #ef4444 (was #1e1b2e at 4.45 — sub-AA) */

  /* Success */
  --interlace-success: #10b981;            /* emerald-500 */
  --interlace-success-foreground: #1e1b2e;

  /* Warning */
  --interlace-warning: #f59e0b;            /* amber-500 */
  --interlace-warning-foreground: #1e1b2e;
}

/* ─────────────────────────────────────────────────────────────────
 *  Bind brand tokens to the shadcn-bare names. Apps that want to
 *  override individual brand values can re-declare them after this
 *  import.
 * ──────────────────────────────────────────────────────────────── */
:root,
.dark,
[data-theme='dark'] {
  --primary: var(--interlace-primary);
  --primary-foreground: var(--interlace-primary-foreground);
  --background: var(--interlace-background);
  --foreground: var(--interlace-foreground);
  --card: var(--interlace-card);
  --card-foreground: var(--interlace-card-foreground);
  --popover: var(--interlace-popover);
  --popover-foreground: var(--interlace-popover-foreground);
  --muted: var(--interlace-muted);
  --muted-foreground: var(--interlace-muted-foreground);
  --accent: var(--interlace-accent);
  --accent-foreground: var(--interlace-accent-foreground);
  --secondary: var(--interlace-secondary);
  --secondary-foreground: var(--interlace-secondary-foreground);
  --border: var(--interlace-border);
  --input: var(--interlace-input);
  --ring: var(--interlace-ring);
  --destructive: var(--interlace-destructive);
  --destructive-foreground: var(--interlace-destructive-foreground);

  /* Override fumadocs-prefixed tokens for AA contrast.
   *
   * Fumadocs `neutral.css` ships `--color-fd-muted-foreground: #737373`,
   * which yields 4.34–4.46:1 contrast against the `bg-fd-card/40-50`
   * surfaces our Section / SectionHeader stories render — just below
   * the WCAG 2.2 AA 4.5:1 floor and gates Storybook a11y CI red.
   *
   * Rebinding to the brand muted-foreground (a darker purple-grey in
   * light, lighter in dark) clears the threshold and keeps brand
   * consistency between shadcn-styled and fumadocs-styled surfaces.
   */
  --color-fd-muted-foreground: var(--interlace-muted-foreground);
}

/* Register the shadcn-bare tokens as Tailwind v4 theme keys so utilities
 * like `bg-card`, `text-foreground`, `border-border`, `bg-primary` are
 * generated. `inline` preserves the `var()` reference, so the runtime
 * `.dark { --background: ... }` overrides above flow through to every
 * utility. Without this block, Tailwind v4 emits no `bg-card` rule
 * regardless of what `--card` resolves to on :root. */
@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
}
